patches.diff:
--- a/src/auth/session.ts
+++ b/src/auth/session.ts
@@ -1,4 +1,8 @@
 import { SessionStore } from './store';

-export function getSession(id: string) {
-  return SessionStore.get(id);
+export function getSession(id: string) { return SessionStore.get(id); }
+
+export function createSession(userId: string): string {
+  const id = crypto.randomUUID();
+  SessionStore.set(id, { userId, createdAt: Date.now() });
+  return id;
 }

--- a/src/auth/login.ts
+++ b/src/auth/login.ts
@@ -1,6 +1,7 @@
 import { verifyPassword } from './crypto';
+import { createSession } from './session';

 export async function handleLogin(email: string, password: string) {
   const user = await findUser(email);
   if (!user || !verifyPassword(password, user.hash)) throw new Error('Invalid credentials');
-  return { token: generateToken(user.id) };
+  return { sessionId: createSession(user.id) };
 }
